exercises.solution_code:
#include <iostream>

struct Plain
{
    int m_value{};
};

struct OneVirtual
{
    int m_value{};
    virtual void f() {}
};

struct TwoVirtuals
{
    int m_value{};
    virtual void f() {}
    virtual void g() {}
};

struct Derived : public OneVirtual
{
    void f() override {}
};

int main()
{
    std::cout << "Plain: " << sizeof(Plain) << '\n';
    std::cout << "OneVirtual: " << sizeof(OneVirtual) << '\n';
    std::cout << "TwoVirtuals: " << sizeof(TwoVirtuals) << '\n';
    std::cout << "Derived: " << sizeof(Derived) << '\n';

    return 0;
}

