exercises.solution_code:
#include <iostream>
#include <string>
#include <vector>

class Base
{
public:
    virtual ~Base() = default;
    virtual std::string identify() const { return "Base"; }
};

class Alpha : public Base
{
public:
    std::string identify() const override { return "Alpha"; }
};

class Beta : public Base
{
    double m_value{};
public:
    std::string identify() const override { return "Beta"; }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<Base*> objects{};
    std::vector<std::string> types{};

    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;
        types.push_back(type);

        if (type == "alpha")       objects.push_back(new Alpha{});
        else if (type == "beta")   objects.push_back(new Beta{});
        else                        objects.push_back(new Base{});
    }

    for (int i{0}; i < n; ++i)
    {
        std::size_t size{ sizeof(Base) };
        if (types[i] == "alpha")      size = sizeof(Alpha);
        else if (types[i] == "beta")  size = sizeof(Beta);

        std::cout << objects[i]->identify() << ' ' << size << '\n';
    }

    for (auto* obj : objects)
        delete obj;

    return 0;
}
